6. 参考代码模式：
```typescript
avPlayer.on('stateChange', async (state: string, reason: media.StateChangeReason) => {
  switch (state) {
    case 'completed':
    case 'stopped':
      await avPlayer.reset();
      avPlayer.url = nextAudioUrl;
      break;
    case 'initialized':
      await avPlayer.prepare();
      break;
    case 'prepared':
      await avPlayer.play();
      break;
    case 'error':
      await avPlayer.reset();
      avPlayer.url = currentAudioUrl;
      break;
  }
});
```

