const fd = fs.openSync(filePath, fs.OpenMode.READ_ONLY);
const stat = fs.statSync(filePath);
try {
  player.fdSrc = { fd: fd.fd, offset: 0, length: stat.size };
  await player.prepare();
  await player.play();
} finally {
  // 只在release后关闭fd
  fs.closeSync(fd);
}
